// Helper to generate markdown for a single insight
function generateMarkdown(insight) {
  const slug = insight.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 60);
  const publishedAt = new Date(insight.published_at || new Date());
  const year = publishedAt.getFullYear();
  const month = String(publishedAt.getMonth() + 1).padStart(2, '0');

  const topics = Array.isArray(insight.topics) ? insight.topics : [];
  const geo = Array.isArray(insight.geo) ? insight.geo : [];
  const citations = Array.isArray(insight.citations) ? insight.citations : [];
  const summaryBullets = Array.isArray(insight.summary_bullets) ? insight.summary_bullets : [];

  let md = `---\ntitle: "${insight.title.replace(/"/g, '\\"')}"\nslug: "${slug}"\npublished_at: "${insight.published_at}"\nstatus: "published"\ntopics:\n${topics.map(t => `  - "${t}"`).join('\n')}\nfreedom_relevance_score: ${insight.freedom_relevance_score}\ncredibility_score: ${insight.credibility_score}\n`;

  if (geo.length > 0) md += `geo:\n${geo.map(g => `  - "${g}"`).join('\n')}\n`;
  md += `citations:\n${citations.map(c => `  - "${c}"`).join('\n')}\n---\n\n# ${insight.title}\n\n**TL;DR:** ${insight.tldr}\n\n## Key Points\n\n${summaryBullets.map(b => `- ${b}`).join('\n')}\n`;
  if (insight.deep_dive_markdown) md += `\n## Deep Dive\n\n${insight.deep_dive_markdown}\n`;
  md += `\n## Sources\n\n${citations.map(c => `- ${c}`).join('\n')}\n`;

  return {
    path: `website/public/content/insights/${year}/${month}/${slug}.md`,
    content: md,
    slug,
    title: insight.title
  };
}

